#!/usr/bin/env node

/**
 * generate-platform-cli-index.js
 *
 * Generates the "All Platform CLI commands" index consumed by
 * platform/reference/platform-cli.mdx, derived from the generated
 * vcluster/cli/vcluster_platform*.md reference pages.
 *
 * Those CLI reference pages are regenerated by an external CLI-docs sync
 * process outside this repo's normal review flow, so a hand-maintained list
 * of commands here would silently drift whenever a platform subcommand is
 * added or removed upstream. This script derives the index directly from
 * the CLI reference files instead, so it can only go stale in a way CI can
 * catch (see --dry-run and .github/workflows/validate-platform-cli-index.yml).
 *
 * This script is idempotent - safe to run multiple times.
 *
 * Usage:
 *   node scripts/generate-platform-cli-index.js [--dry-run] [--verbose]
 *
 * Options:
 *   --dry-run   Compare against the committed output, exit 1 on drift
 *   --verbose   Show detailed output, including commands that fell into
 *               the "Other" bucket because their verb isn't recognized
 */

const fs = require('fs');
const path = require('path');

const PROJECT_ROOT = path.join(__dirname, '..');
const CLI_DIR = path.join(PROJECT_ROOT, 'vcluster/cli');
const OUTPUT_FILE = path.join(PROJECT_ROOT, 'platform/_partials/reference/platform-cli-commands.mdx');
const ROOT_COMMAND_FILE = 'vcluster_platform.md';

const args = process.argv.slice(2);
const isDryRun = args.includes('--dry-run');
const isVerbose = args.includes('--verbose') || isDryRun;

// Top-level verb -> section heading, in render order. A filename verb not
// listed here falls into "Other" automatically (see groupCommands), so a
// brand new top-level subcommand is never silently dropped from the index -
// at worst it lands in "Other" until someone adds it here.
const VERB_HEADINGS = [
  ['start', 'Start'],
  ['login', 'Login'],
  ['logout', 'Logout'],
  ['access-key', 'Access keys'],
  ['connect', 'Connect'],
  ['add', 'Add'],
  ['create', 'Create'],
  ['delete', 'Delete'],
  ['list', 'List'],
  ['get', 'Get'],
  ['set', 'Set'],
  ['share', 'Share'],
  ['sleep', 'Sleep'],
  ['wakeup', 'Wake up'],
  ['backup', 'Backup'],
  ['reset', 'Reset'],
  ['destroy', 'Destroy'],
];
const VERB_ORDER = new Set(VERB_HEADINGS.map(([verb]) => verb));
const OTHER_KEY = 'other';
const OTHER_HEADING = 'Other';

// Upstream data bug: vcluster_platform_wakeup_vcluster.md's one-line
// description is copy-pasted from vcluster_platform_list_vclusters.md
// ("Lists all virtual clusters that are connected to the current platform").
// Override until the upstream CLI reference is fixed (see ENG-12332).
const DESCRIPTION_OVERRIDES = {
  vcluster_platform_wakeup_vcluster: 'Wake up a virtual cluster after it was put to sleep.',
};

function listCommandFiles() {
  return fs
    .readdirSync(CLI_DIR)
    .filter((f) => f.startsWith('vcluster_platform') && f.endsWith('.md') && f !== ROOT_COMMAND_FILE)
    .sort();
}

/**
 * Parse a generated CLI reference file into {label, description, slug, verb}.
 * Relies on the consistent shape of these generated files: YAML frontmatter
 * with a sidebar_label, then a one-line description, then "## Synopsis".
 */
function parseCommandFile(filename) {
  const content = fs.readFileSync(path.join(CLI_DIR, filename), 'utf8');

  const fmMatch = content.match(/^---\r?\n([\s\S]*?)\r?\n---/);
  const frontmatter = fmMatch ? fmMatch[1] : '';
  const labelMatch = frontmatter.match(/^sidebar_label:\s*(.+)$/m);
  const label = labelMatch
    ? labelMatch[1].trim().replace(/^["']|["']$/g, '')
    : filename.replace(/\.md$/, '');

  // Most generated files open with a blank-line-separated description, but
  // at least one (vcluster_platform_get_cluster.md) opens with a redundant
  // "## <command>" heading from an older generator pass. Skip a leading
  // heading line so it doesn't leak into the description column.
  const afterFrontmatter = fmMatch ? content.slice(fmMatch[0].length) : content;
  const withoutLeadingHeading = afterFrontmatter.replace(/^\n*#{1,6}\s+[^\n]*\n/, '\n');
  const descMatch = withoutLeadingHeading.match(/^\n*([^\n]+)\n/);
  const slug = filename.replace(/\.md$/, '');
  const description = DESCRIPTION_OVERRIDES[slug] ?? (descMatch ? descMatch[1].trim() : '');

  // The verb is the path segment right after "vcluster_platform_", e.g.
  // "create" from vcluster_platform_create_vcluster.md, or "access-key" from
  // vcluster_platform_access-key.md.
  const verbMatch = slug.match(/^vcluster_platform_([a-z-]+)/);
  const verb = verbMatch ? verbMatch[1] : '';

  return { label, description, slug, verb };
}

function groupCommands(commands) {
  const groups = new Map();
  for (const verb of VERB_ORDER) groups.set(verb, []);
  groups.set(OTHER_KEY, []);

  for (const cmd of commands) {
    const key = VERB_ORDER.has(cmd.verb) ? cmd.verb : OTHER_KEY;
    groups.get(key).push(cmd);
  }
  return groups;
}

function renderMdx(groups) {
  const lines = [];
  lines.push('{/* Auto-generated by scripts/generate-platform-cli-index.js. Do not edit by hand. */}');
  lines.push(
    '{/* Run `npm run generate-platform-cli-index` to regenerate after vcluster/cli/vcluster_platform*.md changes. */}'
  );
  lines.push('');

  const sections = [...VERB_HEADINGS, [OTHER_KEY, OTHER_HEADING]];
  for (const [verb, heading] of sections) {
    const cmds = groups.get(verb);
    if (!cmds || cmds.length === 0) continue;

    lines.push(`### ${heading}`);
    lines.push('');
    lines.push('| Command | Description |');
    lines.push('| --- | --- |');
    for (const cmd of [...cmds].sort((a, b) => a.label.localeCompare(b.label))) {
      lines.push(`| [\`${cmd.label}\`](/docs/vcluster/cli/${cmd.slug}) | ${cmd.description} |`);
    }
    lines.push('');
  }

  return lines.join('\n');
}

function main() {
  const files = listCommandFiles();
  const commands = files.map(parseCommandFile);
  const groups = groupCommands(commands);
  const output = renderMdx(groups);

  if (isVerbose) {
    console.log(`Found ${commands.length} platform CLI command pages.`);
    const other = groups.get(OTHER_KEY);
    if (other.length > 0) {
      console.log(`[WARN] ${other.length} command(s) fell into "Other" - consider adding their verb to VERB_HEADINGS:`);
      for (const cmd of other) console.log(`  - ${cmd.slug}`);
    }
  }

  if (isDryRun) {
    const existing = fs.existsSync(OUTPUT_FILE) ? fs.readFileSync(OUTPUT_FILE, 'utf8') : null;
    if (existing === output) {
      console.log('[OK] Platform CLI command index is up to date.');
      process.exit(0);
    }
    console.log('[ERROR] Platform CLI command index is out of sync!');
    console.log('Run: npm run generate-platform-cli-index');
    process.exit(1);
  }

  fs.mkdirSync(path.dirname(OUTPUT_FILE), { recursive: true });
  fs.writeFileSync(OUTPUT_FILE, output, 'utf8');
  console.log(`[OK] Wrote ${path.relative(PROJECT_ROOT, OUTPUT_FILE)}`);
  process.exit(0);
}

main();
